action.command:
mkdir -p logs/iter_${RAB_ITERATION} && python - <<'PY'
import json, os
from pathlib import Path
out={}
for fn in ['train.py','model.py','predict.py']:
    p=Path(fn)
    txt=p.read_text() if p.exists() else ''
    out[fn]=txt
    print(f'--- {fn} lines={len(txt.splitlines())} chars={len(txt)} ---')
    lines=txt.splitlines()
    for i,l in enumerate(lines[:80],1):
        if fn=='train.py' or i<=40:
            print(f'{i:03d}: {l[:180]}')
    if len(lines)>80:
        print('...')
        for i,l in enumerate(lines[-40:],len(lines)-39):
            print(f'{i:03d}: {l[:180]}')
Path('logs/iter_'+os.environ.get('RAB_ITERATION','x')+'/source_inspect.json').write_text(json.dumps(out))
print('wrote source_inspect')
PY
